import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox"; // Import LoginBox
import { FaProjectDiagram } from "react-icons/fa"; // Importing an icon
import { Button } from "@/components/ui/button";

const AppLayout = ({ children }) => {
  const [showLogin, setShowLogin] = useState(false);

  const toggleLogin = () => {
    setShowLogin(!showLogin);
  };

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-50 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col justify-center items-center relative">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-6 px-8 shadow-lg w-full text-center flex flex-col items-center animate-fadeIn relative">
          <FaProjectDiagram className="text-5xl text-yellow-300 mb-2 animate-bounce" />
          <h1 className="text-2xl font-semibold tracking-wide">
            🚀 Manage Your Projects Efficiently With
          </h1>
          <h2 className="text-4xl font-extrabold text-yellow-300 mt-2">Proma</h2>

          {/* Login Button */}
          <button
            onClick={toggleLogin}
            className="absolute top-4 right-6 bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
          >
            Login
          </button>
        </header>

        {/* Page Content */}
        <div className="p-6">{children}</div>

        {/* Login Box Popup */}
        {showLogin && (
          <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
            <div className="bg-white p-6 rounded-lg shadow-xl relative">
              <button
                onClick={toggleLogin}
                className="absolute top-2 right-2 text-gray-700 hover:text-gray-900"
              >
                ✖
              </button>
              <LoginBox />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AppLayout;
